import java.util.ArrayList;
import java.util.List;

public class RobotFinder {

    public static List<int[]> findRobots(char[][] matrix, int[] query) {
        List<int[]> robots = new ArrayList<int[]>();
        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[i].length; j++) {
                if (matrix[i][j] == '0' && isValidRobot(matrix, i, j, query)) {
                    robots.add(new int[]{i, j});
                }
            }
        }
        return robots;
    }

    private static boolean isValidRobot(char[][] matrix, int row, int col, int[] query) {
        return isDirectionValid(matrix, row, col, -1, 0, query[0]) &&  // Check left
               isDirectionValid(matrix, row, col, 0, -1, query[1]) &&  // Check top
               isDirectionValid(matrix, row, col, 1, 0, query[3]) &&   // Check right
               isDirectionValid(matrix, row, col, 0, 1, query[2]);     // Check bottom
    }

    private static boolean isDirectionValid(char[][] matrix, int row, int col, int dx, int dy, int distance) {
        for (int i = 1; i <= distance; i++) {
            int newRow = row + i * dx;
            int newCol = col + i * dy;
            if (newRow < 0 || newRow >= matrix.length || newCol < 0 || newCol >= matrix[0].length) {
                return false; // Out of bounds
            }
            if (i != distance && matrix[newRow][newCol] == 'X') {
                return false; // Blocker before the required distance
            }
            if (i == distance && matrix[newRow][newCol] != 'X') {
                return false; // No blocker at the required distance
            }
        }
        return true;
    }

    public static void main(String[] args) {
        char[][] matrix = {
            {'0', 'E', 'E', 'E', 'X'},
            {'E', '0', 'X', 'X', 'X'},
            {'E', 'E', 'E', 'E', 'E'},
            {'X', 'E', '0', 'E', 'E'},
            {'X', 'E', 'X', 'E', 'X'}
        };

        int[] query = {2, 2, 4, 1};
        List<int[]> robots = findRobots(matrix, query);

        for (int[] robot : robots) {
            System.out.println("Robot found at: (" + robot[0] + ", " + robot[1] + ")");
        }
    }
}
